import { MeshEngine, type Task, type AsyncForkResult, type AsyncFoldResult } from './mesh-engine';
import { UnboundedDarkEnergyFork, DisjointDarkMatterFork, type DarkMatterTaskResult } from './dark-fork-topology';
import { type MeshVertex } from './scheduling-mesh';
import { ProgressiveMeshOrchestrator, type RevSignals, type MeshBranch } from '../../aeon/src/flow/ProgressiveMeshOrchestrator';
import { type PackedKnot, toBytes, fromBytes } from './runtime/packed-knot';
import { AtomicKnotSharder } from './atomic-sharder';

/**
 * Dark Sector Atomized Encryption (DSAE)
 * 
 * Principles:
 * 1. Dark Energy Scaling: The search space (atoms) expands unbounded over time.
 * 2. Dark Matter Invisibility: Shards are hidden from Gauge Observation (Race) 
 *    using zero-coupling disjoint threads.
 * 3. Gravity Reconciliation: Re-assembly requires a full Gravity Fold.
 */

export interface DSAEVault {
  shards: AsyncForkResult<DarkMatterTaskResult<Uint8Array> | Uint8Array>;
  expansion: UnboundedDarkEnergyFork;
  orchestrator: ProgressiveMeshOrchestrator;
  shardCount: number;
}

export class DarkSectorVault {
  private engine: MeshEngine;
  private darkMatter: DisjointDarkMatterFork;
  private orchestrator: ProgressiveMeshOrchestrator;

  constructor(engine: MeshEngine) {
    this.engine = engine;
    this.darkMatter = new DisjointDarkMatterFork(engine);
    
    const mockBranch = (dim: 8 | 16 | 32 | 55): MeshBranch => ({
      dim, estimatedCost: 0, run: () => ({ value: [] })
    });
    this.orchestrator = new ProgressiveMeshOrchestrator([
      mockBranch(8), mockBranch(16), mockBranch(32), mockBranch(55)
    ]);
  }

  /**
   * Encrypts a secret by atomizing it into self-contained Dark Matter shards.
   */
  async encrypt(secret: PackedKnot | Uint8Array, shardCount: number, signals: RevSignals): Promise<DSAEVault> {
    const data = (secret as any).crossings ? toBytes(secret as PackedKnot) : (secret as Uint8Array);
    
    // Atomize into self-contained shards
    const atomicShards = AtomicKnotSharder.shard(data, shardCount);
    
    const forkResult = this.darkMatter.forkMatter(0, async (vertex) => {
      // Find the index of this vertex in the current fork's radial targets
      // This is a bit of a hack since forkMatter hides the targets, 
      // but in this mesh topology, id % shardCount should work if id is 1..N.
      // Better: we'll use a local counter or pass index if possible.
      // For now, we'll keep the % but ensure it covers 0..shardCount-1.
      const sliceIdx = vertex.id % shardCount;
      return atomicShards[sliceIdx]!;
    });

    const rev = this.orchestrator.computeRev(signals);
    const expansionDelay = Math.max(1, 100 * (1 - rev));
    
    const expansion = new UnboundedDarkEnergyFork(this.engine, expansionDelay, 8192);
    expansion.start(async () => 'dark-energy-noise');

    return { shards: forkResult, expansion, orchestrator: this.orchestrator, shardCount };
  }

  /**
   * Reconstructs the secret using a Gravity Fold.
   */
  async decrypt(vault: DSAEVault): Promise<Uint8Array> {
    const fold = await this.darkMatter.gravityFold(vault.shards);
    
    const shardsMap = new Map<number, Uint8Array>();
    fold.results.forEach(r => {
      const result = (r.result as DarkMatterTaskResult<Uint8Array>).intrinsicCharge;
      // AtomicKnotSharder.reassemble expects raw shards, it will handle internal indexing.
      // We just need to make sure we don't have duplicates from multi-hub folds.
      const view = new DataView(result.buffer, result.byteOffset, result.byteLength);
      const shardIdx = view.getUint32(8, false);
      if (!shardsMap.has(shardIdx)) {
        shardsMap.set(shardIdx, result);
      }
    });

    // Reassemble handles the sorting by index internally
    return AtomicKnotSharder.reassemble(Array.from(shardsMap.values()));
  }

  /**
   * Reconstructs as a PackedKnot if the data was originally a knot.
   */
  async decryptKnot(vault: DSAEVault): Promise<PackedKnot> {
    const bytes = await this.decrypt(vault);
    return fromBytes(bytes);
  }
}